import type { FilterFieldSuggestion } from '../suggestions/Suggestion.types.js';
import type { FilterFieldSuggestionGroup } from '../suggestions/SuggestionGroup.types.js';
import type { FilterFieldFlatNode } from '../types/conversion-utils.js';
import type {
  FilterFieldBigIntNode,
  FilterFieldBooleanNode,
  FilterFieldComparisonOperatorNode,
  FilterFieldDurationNode,
  FilterFieldErrorNode,
  FilterFieldExistsOperatorNode,
  FilterFieldGroupNode,
  FilterFieldInclusionOperatorNode,
  FilterFieldJSONPathNode,
  FilterFieldKeyNode,
  FilterFieldLeafNode,
  FilterFieldListNode,
  FilterFieldNode,
  FilterFieldNumberNode,
  FilterFieldSearchOperatorNode,
  FilterFieldStatementNode,
  FilterFieldStringNode,
  FilterFieldVariableNode,
} from '../types/tree-nodes.js';

/**
 * Check whether the given node is a filter field JSONPath node
 * @internal
 */
export function isFilterFieldJSONPathNode(
  node: unknown,
): node is FilterFieldJSONPathNode {
  return (
    typeof node === 'object' &&
    (node as FilterFieldJSONPathNode).type === 'JSONPath'
  );
}

