/**
 * Check whether the given node is a filter field list node.
 * @public
 */
export function isFilterFieldListNode(
  node: unknown,
): node is FilterFieldListNode {
  return (
    typeof node === 'object' &&
    (node as FilterFieldLeafNode).textValue !== undefined &&
    Array.isArray((node as FilterFieldLeafNode).value)
  );
}

/**
 * Check if the given token is a node holding a value.
 * Not necessarily a leaf node. E.g. a List has a value,
 * but the value consists of other tokens.
 * @internal
 */
export function isFilterFieldValueNode(
  node: unknown,
): node is FilterFieldLeafNode {
  return (
    typeof node === 'object' &&
    (node as FilterFieldLeafNode).textValue !== undefined
  );
}

/**
 * Check whether the given node is a filter field leaf node.
 * @public
 */
export function isFilterFieldLeafNode(
  node: unknown,
): node is FilterFieldLeafNode {
  return (
    typeof node === 'object' &&
    (node as FilterFieldLeafNode).textValue !== undefined &&
    !Array.isArray((node as FilterFieldLeafNode).value)
  );
}

/**
 * Check if the given token is a filter value.
 * @internal
 */
export function isFilterValue(
  token: FilterFieldLeafNode | FilterFieldListNode,
): boolean {
  const valueTypes: (FilterFieldLeafNode['type'] | 'List')[] = [
    'String',
    'Number',
    'Boolean',
    'Duration',
    'List',
    'Error',
  ];

  return valueTypes.includes(token.type);
}

/**
 * Returns whether the current operator is valid for a position operator (start-with / ends-with / contains).
 * Only equals, not equals, and ends-with/not-ends-with (will be converted to contains/not-contains) are valid values.
 * @internal
 */
export function isValidPositionOperator(
  node: FilterFieldStatementNode,
): boolean {
  return (
    node.comparisonOperator?.value === '=' ||
    node.comparisonOperator?.value === '!=' ||
    node.comparisonOperator?.value === 'ends-with' ||
    node.comparisonOperator?.value === 'not-ends-with'
  );
}

/**
 * Returns whether the current operator is a a LogicalOperator. Either it has the type LogicalOperator or it has the
 * type Error and 'OR' or 'AND' as value (if the LogicalOperator is in an invalid position or 'OR' is used in the basic syntax).
 * @internal
 */
export function isLogicalOperator(
  node: FilterFieldFlatNode | FilterFieldNode,
): boolean {
  return (
    node &&
    (node.type === 'LogicalOperator' ||
      (node.type === 'Error' && (node.value === 'OR' || node.value === 'AND')))
  );
}

/**
 * Returns whether the given value is a filter field suggestion group.
 * @internal
 */
export function isFilterFieldSuggestionGroup(
  value: unknown,
): value is FilterFieldSuggestionGroup {
  return (
    typeof value === 'object' &&
    ((value as FilterFieldSuggestionGroup).label !== undefined ||
      (value as FilterFieldSuggestionGroup).suggestions !== undefined)
  );
}

/**
 * Returns whether the given value is a filter field suggestion.
 * @internal
 */
export function isFilterFieldSuggestion(
  value: unknown,
): value is FilterFieldSuggestion {
  const suggestionValue = value as FilterFieldSuggestion;
  return (
    typeof value === 'object' &&
    (suggestionValue.value !== undefined ||
      suggestionValue.displayValue !== undefined ||
      suggestionValue.insertionStrategy !== undefined)
  );
}
